import React from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { ShoppingCart, Bell } from 'lucide-react';
import beequeenLogo from '../assets/beequen.png';

const Header = () => {
  const navigate = useNavigate();

  return (
    <header className="bg-black shadow-md">
      <div className="max-w-7xl mx-auto px-4 py-4">
        <div className="flex justify-between items-center">
          {/* Seção de pesquisa */}
          <div className="flex-1">
            <input
              type="search"
              placeholder="Pesquisar..."
              className="w-full max-w-xs px-4 py-2 rounded-lg border border-amber-400 focus:outline-none focus:ring-2 focus:ring-amber-400"
            />
          </div>

          {/* Logo central */}
          <div className="flex-1 flex justify-center">
            <Link to="/" className="block w-20 h-20">
              <img 
                src={beequeenLogo}
                alt="Beequeen Logo" 
                className="w-full h-full object-contain"
              />
            </Link>
          </div>

          {/* Navegação e ícones */}
          <div className="flex-1 flex justify-end items-center space-x-8">
            <nav className="flex space-x-8">
              <Link to="/" className="text-amber-400 hover:text-amber-300">LINK 1</Link>
              <Link to="/" className="text-amber-400 hover:text-amber-300">LINK 2</Link>
              <Link to="/wishlist" className="text-amber-400 hover:text-amber-300">WISHLIST</Link>
            </nav>
            <div className="flex items-center space-x-4">
              <Bell className="h-6 w-6 text-amber-400 cursor-pointer hover:text-amber-300" />
              <ShoppingCart className="h-6 w-6 text-amber-400 cursor-pointer hover:text-amber-300" />
            </div>
          </div>
        </div>
      </div>
    </header>
  );
};

export default Header;
